SELECT
    m.*,
    dr.requirement_name,
    d.resource_name
FROM data_requirement_match m
LEFT JOIN data_requirement dr ON m.requirement_id = dr.id AND dr.is_del = 0
LEFT JOIN data_resource d ON m.resource_id = d.resource_id AND d.is_del = 0

    m.is_del = 0

        AND m.requirement_id = #{requirementId}


        AND m.resource_id = #{resourceId}


        AND m.match_status = #{matchStatus}


        AND m.match_type = #{matchType}


        AND m.match_score >= #{minScore}


ORDER BY m.match_score DESC, m.create_date DESC

    LIMIT #{offset}, #{pageSize}

